import React from "react";
import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  // Check login status
  const isLoggedIn = localStorage.getItem("isLoggedIn") === "true";

  const handleLogout = () => {
    localStorage.removeItem("isLoggedIn");
    alert("Logged out successfully");
    navigate("/login");
  };

  return (
    <header style={styles.navbar}>

      {/* Logo */}
      <div style={styles.logoContainer}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
          alt="logo"
          style={styles.logoImg}
        />
        <h2 style={styles.logoText}>DocBook</h2>
      </div>

      <ul style={styles.navLinks}>
        
        {isLoggedIn ? (
          <>
            <li style={styles.link} onClick={() => navigate("/home")}>Home</li>
            <li style={styles.link}>Doctors</li>
            <li style={styles.link}>My Appointments</li>
            <li style={styles.link}>Profile</li>
            <li style={styles.logout} onClick={handleLogout}>Logout</li>
          </>
        ) : (
          <>
            <li style={styles.link} onClick={() => navigate("/login")}>Login</li>
            <li style={styles.link} onClick={() => navigate("/")}>Register</li>
          </>
        )}

      </ul>
    </header>
  );
}

export default Navbar;
